import React from 'react';
import logo from '../assets/logo.png';

const FOOTER_COLS = [
  {
    title: 'Shop',
    links: ['New Arrivals', 'Best Sellers', 'Sale', 'Anime', 'Western']
  },
  {
    title: 'Help',
    links: ['Track Order', 'Shipping Policy', 'Returns & Refunds', 'FAQ', 'Contact Us'],
  },
  {
    title: 'Company',
    links: ['About Us', 'Careers', 'Privacy Policy', 'Terms & Conditions'],
  },
];

export default function Footer() {
  return (
    <footer className="bg-[#0e0e0e] text-white px-7 pt-12 pb-7">

      {/* Top grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10 mb-10">

        {/* Brand col */}
        <div>
          {/* Logo — invert filter so it shows on dark bg */}
          <div className="flex items-center gap-3 mb-4">
            <img
              src={logo}
              alt="AnimeMonkey"
              className="h-10 w-auto object-contain"
              style={{ filter: 'brightness(0) invert(1)' }}
            />
            <span className="font-black text-lg text-white tracking-tight" style={{ fontFamily: 'Playfair Display, serif' }}>
              AnimeMonkey
            </span>
          </div>
          <p className="text-xs text-gray-600 leading-loose max-w-[200px]">
            India's premium anime merch destination. Figures, cosplay, clothing & collectibles from every universe you love.
          </p>
          {/* Socials */}
          <div className="flex gap-2 mt-4">
            {['𝕏', '📸', '▶', 'in'].map(s => (
              <button
                key={s}
                className="w-8 h-8 border border-gray-800 rounded-lg flex items-center justify-center text-gray-600 hover:border-gray-500 hover:text-white transition-all text-sm"
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        {/* Link cols */}
        {FOOTER_COLS.map(col => (
          <div key={col.title}>
            <div className="text-[10px] font-bold tracking-[2px] uppercase text-gray-600 mb-4">
              {col.title}
            </div>
            {col.links.map(link => (
              <a
                key={link}
                href="#"
                className="block text-sm text-gray-700 hover:text-white mb-2.5 transition-colors"
              >
                {link}
              </a>
            ))}
          </div>
        ))}
      </div>

      {/* Bottom bar */}
      <div className="border-t border-gray-900 pt-5 flex flex-col sm:flex-row justify-between items-center gap-3">
        <p className="text-xs text-gray-700">
          © 2025 AnimeMonkey. Fan art & merch — not official unless explicitly stated.
        </p>
        <p className="text-xs text-gray-700">
          UPI &nbsp;·&nbsp; Cards &nbsp;·&nbsp; &nbsp;·&nbsp; COD &nbsp;·&nbsp; Free shipping on ₹999+
        </p>
      </div>
    </footer>
  );
}
